    // Adaptive simulated annealing parameters
    static double temperature = 10.0; // Higher initial temp for broader exploration
    static double cooling_rate = 0.95; // Slower cooling
    static const double min_temperature = 0.001; // Lower minimum for fine-tuning
    static int iteration = 0;
    static int accept_count = 0; // Track acceptance rate

    double best_arrival = std::numeric_limits<double>::max();
    double best_area_flow = std::numeric_limits<double>::max();
    float best_area = std::numeric_limits<float>::max();
    uint32_t best_size = UINT32_MAX;
    uint8_t best_cut = 0u;
