        static double last_temp = temperature;
        if (temperature > min_temperature) {
            double accept_rate = accept_count / (double)(iteration + 1);
            if (accept_rate < 0.1) {
                temperature *= 0.98; // Cool faster if few acceptances
            } else if (accept_rate > 0.3) {
                temperature *= 0.995; // Cool slower if many acceptances
            } else {
                temperature *= cooling_rate;
            }
            // Prevent temperature from increasing accidentally
            temperature = min(temperature, last_temp);
            last_temp = temperature;
        }
      }

